insert into alternatives (id, slug, name, brand, basis_text, basis_confidence, basis_sources, affiliate_url, affiliate_type, category, image_url, asin, swap_type) values
  ('5835671a-b34e-458e-924d-ba77c0596d48', 'bobs-red-mill-baking-soda', 'Baking Soda', 'Bob''s Red Mill', 'Founder Bob Moore was a committed Christian; multiple sources document his faith as the explicit motivation for company policy, including giving the company to employees via an ESOP.', 1, ARRAY['https://en.wikipedia.org/wiki/Bob_Moore_(executive)', 'https://www.klove.com/news/faith/founder-of-bob-s-red-mill-committed-christian-generous-boss-9757'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Bob''s%20Red%20Mill%20Baking%20Soda', NULL, 'christian'),
  ('933c3f42-9758-4c5e-8fd6-e80d20e25920', 'boll-weevil-foaming-hand-wash', 'Foaming Hand Wash', 'Boll Weevil Soap Company', 'Explicitly self-identifies as a Christian-owned family soap business, citing Colossians 3:17 on its own About page. Note: only the Foaming Hand Wash is confirmed available on Amazon — Boll Weevil''s bar soap and body wash are not, and require a direct affiliate relationship instead.', 2, ARRAY['https://bollweevilsoapcompany.com/pages/about-us', 'https://www.amazon.com/Foaming-Boll-Weevil-Soap-Company/dp/B08RF27781'], NULL, 'amazon', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Boll%20Weevil%20Foaming%20Hand%20Wash', 'B08RF27781', 'christian'),
  ('d5f8ea86-8d71-4d0c-afe4-67eae178b214', 'faithfully-natural-soap-co', 'Soap / Body Wash', 'Faithfully Natural Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://faithfullynaturalsoapco.com/pages/about-us'], 'https://faithfullynaturalsoapco.com', 'direct', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Faithfully%20Natural%20Soap%20Co.', NULL, 'christian'),
  ('a87c3228-6297-4eb5-8a77-668cab87f58b', 'pure-hearts-clean-hands-soap-co', 'Soap / Body Wash', 'Pure Hearts & Clean Hands Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://phchnaturalsoap.net/about-us/'], 'https://phchnaturalsoap.net', 'direct', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Pure%20Hearts%20%26%20Clean%20Hands', NULL, 'christian'),
  ('944e4ebf-b967-49ba-bf4d-e414b0f7c76f', 'branch-basics-all-purpose-concentrate', 'All-Purpose Cleaner Concentrate', 'Branch Basics', 'Co-founder Allison Evans states in a published interview, "we share a common faith, which we all fall back on," and founders discuss their Christian faith on the Thriving Beyond Belief podcast.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://thrivingbeyondbelief.com/046-branch-basics-with-allison-evans-marilee-nelson/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20All-Purpose', NULL, 'christian'),
  ('19d4a170-910b-4920-a94a-1f9f7d243fff', 'branch-basics-oxygen-boost', 'Oxygen Boost Stain Remover', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Oxygen%20Boost', NULL, 'christian'),
  ('84d7c2c3-c36f-4f72-bb49-1610a86ffca2', 'provherbs-herbal-supplements', 'Herbal Supplements / Tinctures', 'Provherbs', 'Company''s own "Our Story" page: "we look first to Christ. He is the center in all that we do."', 1, ARRAY['https://provherbs.com/pages/our-story'], 'https://provherbs.com', 'direct', 'Supplements', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Provherbs%20Supplements', NULL, 'christian'),
  ('cfde0c8b-3876-44fd-abf2-f1e320dfd02a', 'eleven86-artesian-water', 'Real Artesian Water', 'Eleven86', 'Company''s own tagline: "Faith in every drop. Purpose in every bottle."', 1, ARRAY['https://www.eleven86water.com/our-story'], 'https://www.eleven86water.com', 'unconfirmed', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Eleven86%20Water', NULL, 'christian'),
  ('fc71405e-5dff-4635-9c64-0b4b0c3c144d', 'bold3-coffee', 'Coffee (whole bean & ground)', 'BOLD3 Coffee', '501(c)(3) Christian nonprofit ministry. Own listing states: "BOLD3 Coffee is a Christian Non-profit Ministry on a mission to empower others to be BOLD and spread the Hope of Christ worldwide." Every bag purchased delivers God''s Word into the hands of 3 children.', 1, ARRAY['https://www.amazon.com/BOLD3-coffee-Colombian-Ethiopian-Nicaragua/dp/B07F2J6MHV', 'https://www.bold3.org/'], NULL, 'amazon', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=BOLD3%20Coffee', 'B07F2J6MHV', 'christian'),
  ('87326a1a-5fa9-4e1e-ac8c-275a5551872b', 'palm-beach-herbal-tea', 'Herbal Tea', 'Palm Beach Herbal Tea Company', 'Explicitly self-identifies as a "Christian based, family-owned herbal tea company" on its own site.', 1, ARRAY['https://palmbeachherbalteas.com/pages/our-story'], NULL, 'amazon', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Palm%20Beach%20Herbal%20Tea', NULL, 'christian'),
  ('20b54054-e2ef-4cd8-97cf-0312831dc17b', 'everylife-diapers-wipes', 'Diapers + Wipes', 'EveryLife', 'Co-founders explicitly state "every child is a miracle from God"; company''s own mission page: "We unapologetically choose to celebrate life. Every child is a gift from above."', 1, ARRAY['https://everylife.com/pages/our-mission', 'https://www.oursundayvisitor.com/meet-the-founders-of-everylife-a-new-pro-life-diaper-company/'], 'https://everylife.com', 'unconfirmed', 'Baby Products', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=EveryLife%20Diapers', NULL, 'christian'),
  ('64b9e8da-2438-42de-8d31-28d048d24258', 'earth-eden-diapers', 'Diapers', 'Earth & Eden', 'Not a confirmed Christian-founded brand, but the closest Amazon-available, non-toxic, plant-based diaper option — offered as a secondary pick alongside EveryLife.', 2, ARRAY['https://www.earthandedenbrand.com/', 'https://www.amazon.com/Earth-Eden-Baby-Diapers-Count/dp/B07DYLJHLB'], NULL, 'amazon', 'Baby Products', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Earth%20%26%20Eden%20Diapers', 'B07DYLJHLB', 'christian'),
  ('246a04b0-1787-4c3e-8522-cd28994e0d0e', 'branch-basics-dishwasher-tablets', 'Dishwasher Tablets', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://www.amazon.com/Branch-Basics-Dishwasher-Tablets-Fragrance-Free/dp/B0GNT5N4SP'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Dishwasher%20Tablets', 'B0GNT5N4SP', 'christian'),
  ('317f0817-4874-4d18-a8f2-149fe6ff2d4b', 'branch-basics-laundry-detergent-powder', 'Laundry Detergent – 4lbs (120 loads), Powder', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate. Plant & mineral-based powder formula, plastic-free and fragrance-free.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Laundry%20Powder', 'B0GQ665H45', 'christian'),
  ('8530e9bd-a6cc-46e2-a23c-8fbc55c3cd63', 'branch-basics-concentrate-oxygen-boost-bundle', 'Concentrate (33.8 oz) + Oxygen Boost (4 lbs) Bundle', 'Branch Basics', 'Concentrate replaces all-purpose cleaners and can be diluted for surface scrubbing; Oxygen Boost acts as a natural scouring powder and grout cleaner. Sold as a confirmed bundle listing on Amazon. Same founder faith basis as other Branch Basics entries.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Bundle', NULL, 'christian'),
  ('fd54b078-de33-499d-aeab-5ea599933a56', 'toups-and-co-organics', 'Makeup & Skincare', 'Toups & Co. Organics', 'Christian family-owned, confirmed on the company''s own About page.', 1, ARRAY['https://toupsandco.com/pages/about-us'], NULL, 'amazon', 'Beauty & Makeup', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Toups%20%26%20Co.%20Organics', NULL, 'christian'),
  ('a7f1e1ee-bd73-4d8b-bfde-46330da612ed', 'jes-organics', 'Makeup, Skincare & Supplements', 'JES Organics', 'Own Amazon storefront states "Christian-based company founded in 2006."', 1, ARRAY['https://www.amazon.com/stores/JESOrganics/Homepage/page/34BCD59B-5770-4397-84F6-721513DA72D3'], NULL, 'amazon', 'Beauty & Makeup', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=JES%20Organics', NULL, 'christian'),
  ('685316a9-0bd2-412d-996b-8913fe03d3c6', 'hosanna-aroma', 'Christian Fragrance', 'Hosanna Aroma', 'Own website states "unapologetically Christian," Scripture-inspired, husband-and-wife team in Colorado, launched April 2024.', 1, ARRAY['https://hosanna-aroma.com/'], 'https://hosanna-aroma.com', 'direct', 'Beauty & Fragrance', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Hosanna%20Aroma', NULL, 'christian'),
  ('1b327324-b07b-46db-b889-582bfa4de017', 'risen-fragrances', 'Christian Fragrance', 'Risen Fragrances', '"Exists to glorify God"; each scent is paired with Scripture, and $1 per bottle funds Bible distribution.', 1, ARRAY['https://risenfragrances.com/'], 'https://risenfragrances.com', 'direct', 'Beauty & Fragrance', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Risen%20Fragrances', NULL, 'christian'),
  ('71cbeb3f-19a3-4d1f-9ec6-379251962e20', 'leaf-razor-chrome', 'Leaf Razor (All-Metal Safety Razor, Chrome)', 'Leaf Shave', 'Clean/non-toxic alternative: all-metal, plastic-free razor with a pivoting head and no toxic shaving-strip chemicals. No Christian-founded claim has been found for Leaf Shave — this is offered as a clean swap, not a faith-based one.', 1, ARRAY['https://www.amazon.com/dp/B09QB2Y263', 'https://leafshave.com/'], NULL, 'amazon', 'Beauty & Personal Care', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Leaf%20Razor', 'B09QB2Y263', 'clean'),
  ('89a1bcc8-7fd1-4471-bcbb-197ad5953332', 'divine-shine-lip-gloss', 'Divine Shine Lip Gloss', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/divine-shine-lip-gloss-1?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/Divine_Shine_Lipgloss.png?v=1773108400&width=980', NULL, 'christian'),
  ('064e4cc8-c81c-46b9-ae3d-b3ee9e596595', 'velvet-lips-matte-lipstick', 'Velvet Lips Matte Lipstick', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/velvet-lips-matte-lipstick?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/VelvetLipstickColors.png?v=1774359692&width=1946', NULL, 'christian'),
  ('a25e6a3c-65f4-43fd-86fc-79e70de21c2a', 'tallow-cream-foundation', 'Tallow Cream Foundation', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/tallow-cream-foundation?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/TALLOW_CREAM_FOUNDATION.png?v=1765925591&width=1240', NULL, 'christian'),
  ('07e3a8d1-0b4d-4c91-b918-31433439d176', 'the-lash-stop-clean-mascara', 'The Lash Stop Clean Mascara', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/the-lash-stop-clean-mascara-1?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/TheLashStopMascaraSquare.png?v=1775084184&width=980', NULL, 'christian'),
  ('dc74a677-1f79-4908-b609-a4e3f41be3f4', 'tallow-skin-first-foundation', 'Tallow Skin-First Foundation', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/tallow-skin-first-foundation?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/TallowSkin-FirstFoundation.png?v=1772142676&width=980', NULL, 'christian'),
  ('48700f75-e891-46c7-8093-09c564a28ae7', 'wisdom-eau-de-parfum', 'Wisdom Eau de Parfum', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/wisdom-eau-de-parfum-30ml-1-0-fl-oz?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Fragrance', 'https://www.christianbeautyco.com/cdn/shop/files/wisdom1x1.png?v=1780080075&width=1240', NULL, 'christian'),
  ('12e429dc-ede4-44af-a988-2865f92a56fa', 'divine-healing-desert-stem-cell-moisturizer', 'Divine Healing Desert Stem Cell Moisturizer', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/divine-healing-desert-stem-cell-moisturizer?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/DivineHealing_129371b6-1ec2-4101-a22f-4c1d4b858383.jpg?v=1752242318&width=1946', NULL, 'christian');
insert into associations (product_id, claim_text, source_urls, confidence_tier, theme_tag, date_checked) values
  ('2b37670b-da97-41a5-a583-b76fe90fa813', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-01'),
  ('6890b08f-dc37-43ef-abf0-bd6a1af8bf9b', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-01'),
  ('4d68b3f3-5a25-482f-ad54-35e3321b0d91', 'Entire collection is structured as a tarot-style "deck" of named fortune cards (The Illusionist, The Sovereign, The Sage, and more). Each bottle includes a QR code for a "shower reading" and a daily "manifestation." Method''s own product copy reads: "Are you ready to hear your fortune? Shoot for the stars today with a body wash that offers a glimpse into your future." This is scoped to the limited-edition Shower Readings line only — Method''s everyday cleaners carry no such theme and are not flagged.', ARRAY['https://methodproducts.com/pages/shower-readings', 'https://www.ulta.com/p/limited-edition-shower-readings-body-wash-pimprod2052565'], 1, 'fortune-telling', '2026-07-01'),
  ('54fe7d9c-2f0a-423d-8582-5c90f0b45c7d', 'The mascot was deliberately designed as a genie at P&G''s own direction. A 2014 NYT obituary for original illustrator Richard Black quotes P&G''s communications manager: the company wanted "magic from a bottle" represented by a genie, and the artist was directed to draw one. Genies/jinn originate in Arabic and Islamic folklore.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('1eb041a7-3a39-41d2-92eb-0669dcb6632f', 'Named after Ajax (Telamonian Ajax), Greek mythological hero of the Trojan War, second in strength only to Achilles. Current marketing leans into it directly: "Stronger than dirt," with copy describing customers as "everyday heroes."', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-01'),
  ('e2792094-14c6-424d-a6ce-814c5569410b', 'Directly named after the Greek/Roman hero Hercules. The company''s own current product pages use the line "Behold the power of Hercules, products built to last and trusted by plumbers."', ARRAY['https://www.oatey.com/products/hercules-glug-kitchen-liquid-drain-opener--782826565'], 1, 'greek-mythology', '2026-07-01'),
  ('169e2670-fe36-4a95-8e52-91e7d60bf8d8', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('a9e871b1-8fad-4b62-9e4d-77a0b87b8cab', 'Founded by Yogi Bhajan, who introduced Kundalini Yoga to the US; the tea recipe and brand are explicitly built on Ayurvedic philosophy. The company''s own "our story" copy still cites Ayurveda as the foundation.', ARRAY['https://en.wikipedia.org/wiki/Yogi_Tea'], 1, 'ayurvedic', '2026-07-01'),
  ('d985760a-ae09-4ae0-ab18-e5fce1e89954', 'Documented marketing campaigns built on witchcraft/occult themes: the company hired a self-described witch doctor in 2019 to publicly "hex" inventory as a Halloween stunt, and sold "sell your soul" branded merchandise with a mock contract for the buyer''s "Eternal Soul." These campaigns themselves are documented fact; describing the brand as "satanic" is contested commentary, not a company statement.', ARRAY['https://www.adweek.com/creativity/drink-at-your-own-risk-liquid-death-hires-witch-doctor-to-hex-its-water/', 'https://www.westernjournal.com/liquid-death-water-brand-offered-buy-customers-souls-even-offers-contract-put-satanic-deal-writing/'], 2, 'occult-marketing', '2026-07-01'),
  ('ff277ca7-a082-475f-97ff-4735b1cacc9e', 'Named directly after Gaia, the Greek primordial Earth goddess and mother of all life in Greek mythology. Confirmed by the founder''s own company history (founded 1986/1987 by herbalist Ric Scalzo).', ARRAY['https://www.peoplespharmacy.com/articles/introducing-gaia-herbs'], 1, 'greek-mythology', '2026-07-01'),
  ('b414e522-2c25-4438-a453-4467abc992e5', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner — P&G''s own communications manager confirmed to the NYT that the mascot was deliberately designed as a genie.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('5604aac6-a4c5-4de4-8ab8-b1f1de0dcec3', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('59bb18ff-2419-4041-a1e8-814522c87452', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. The company''s own website states: "Our name is inspired by an ancient Iroquois philosophy which instructs that in our every deliberation, we must consider the impact of our decisions on the next seven generations."', ARRAY['https://www.seventhgeneration.com/blog/origin-our-name-seventh-generation', 'https://www.fastcompany.com/665006/great-law-iroquois-confederacy'], 1, 'indigenous-philosophy', '2026-07-01'),
  ('2b302380-7992-4cfc-af2c-dd72a4e1e58b', 'Logo is a twin-tailed siren from Greek mythology, confirmed on the company''s own "Story of the Siren" page: "it depicted a siren, a seductive twin-tailed mermaid from Greek mythology who enticed passing sailors to their doom with her enchanting song."', ARRAY['https://about.starbucks.com/history/the-story-of-the-siren/'], 1, 'greek-mythology', '2026-07-01'),
  ('f8d77689-3530-429f-ba3f-93f4becaebdf', 'Name and branding deliberately center on death-themed imagery. The company''s own website states: "To some, a death wish may sound irresponsible, morbid, a step too far — but we believe it is the boldest sign of living life to the fullest." This is secular dark/death-themed branding, not tied to a specific mythology or occult practice.', ARRAY['https://www.forbes.com/sites/forbestreptalks/2016/02/09/meet-the-entrepreneur-behind-the-super-bowl-coffee-ad/', 'https://en.wikipedia.org/wiki/Death_Wish_Coffee'], 1, 'secular-death-themed', '2026-07-01'),
  ('81bf6854-92f3-4834-a7ba-f04c3544c513', 'Founder Jessica Alba publicly shared Instagram content in August 2024 involving occult/spiritual practices (numerology, astrology, crystals, and sage burning). Alba had stepped down as Chief Creative Officer in April 2024, before the posts, so she was no longer a company officer at the time, and the brand''s own products carry no occult imagery or branding. This is the founder''s personal social media activity, not a company branding decision.', ARRAY['https://www.instagram.com/p/C_bp7Qpu-hr/'], 2, 'founder-personal-conduct', '2026-07-01'),
  ('83573a4a-5e04-414d-a071-751df8a59aff', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history. Same brand-wide association as the Arm & Hammer baking soda entry.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-03'),
  ('a7a14757-292f-4a69-9b66-a36f6c2cf717', 'Named after Ajax (Telamonian Ajax), the Greek mythological hero of the Trojan War. Same brand-wide association as the Ajax Powder Cleanser entry.', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-03'),
  ('c3e2ae4a-185f-4930-ab9a-922d3a546e2e', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. Same brand-wide association as the Seventh Generation Laundry Detergent entry.', ARRAY['https://www.seventhgeneration.com/blog/more-than-a-name', 'https://en.wikipedia.org/wiki/Seventh_Generation_Inc.'], 1, 'indigenous-philosophy', '2026-07-03'),
  ('4ac7addc-da71-432b-b4d8-794f28884d5c', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('0d214b0e-6f50-47f0-a727-ea6a44fb3d68', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('861c2f64-f46e-4fbf-b8de-5f38fa2ad2b8', 'Founder Amanda Chantal Bacon describes the company as "a cosmic beacon" in her own interviews, references astrology and crystal energy throughout the brand''s marketing, and publicly stated of a stolen store crystal, "You do not want the energy of a stolen crystal." Company''s own marketing describes Moon Juice as "a healing force, an etheric potion, a cosmic beacon."', ARRAY['https://www.theguardian.com/lifeandstyle/2015/jan/16/moon-juice-food-for-beautiful-people', 'https://moonjuice.com/pages/about'], 1, 'astrology-crystal-energy', '2026-07-03'),
  ('b535f13c-5dc3-422d-93b5-026d4afb99e0', 'Bottle is a five-pointed star, described in the company''s own marketing as "a celestial bottle: a five-pointed star evoking womanhood, protection and destiny." Company''s own copy calls it "a cosmic object that appears supernaturally out of space" and "the embodiment of dreams."', ARRAY['https://www.mugler.com/en-us/angel', 'https://en.wikipedia.org/wiki/Angel_(fragrance)'], 1, 'celestial-supernatural', '2026-07-03'),
  ('91f6f9d8-41c8-4cf2-b43d-4adf182d08e8', 'Named after Venus, the Roman goddess of love and beauty. Company''s own brand platform and tagline: "Reveal the goddess in you." The company''s own brand team confirmed the internal creative platform as "every woman can feel like a goddess."', ARRAY['https://gillette.com/en-us/venus', 'https://en.wikipedia.org/wiki/Gillette_Venus'], 1, 'roman-mythology', '2026-07-03');
